// Generate 4 follow-up runs with proper timing
const base = $json;

// Create 4 runs: Week 1 (immediate), Week 2-4 (7 days apart)
const runs = [1, 2, 3, 4].map((weekNumber, index) => ({
  json: { 
    ...base, 
    weekNumber: weekNumber, 
    waitDays: index === 0 ? 0 : 7  // First run immediate, others wait 7 days
  }
}));

console.log("Generated runs:", runs.length);
return runs;

// EXTRACT TASK ID FROM WEBHOOK EVENTS
// Use this in Node 2: Extract Task ID

const webhookData = $input.first().json;

console.log("=== WEBHOOK DEBUG ===");
console.log("Full webhook data:", JSON.stringify(webhookData, null, 2));

let taskId = null;

// The webhook gives us events, we need to find the task ID
if (Array.isArray(webhookData)) {
  console.log("Webhook data is an array with", webhookData.length, "items");

  // Look for the task in the events
  for (const item of webhookData) {
    console.log("Checking item:", item);

    // Check if this item is a task (not a story)
    if (item.resource_type === 'task' && item.gid) {
      taskId = item.gid;
      console.log("Found task ID:", taskId);
      break;
    }

    // Alternative: if it's an event with a task resource
    if (item.resource && item.resource.resource_type === 'task') {
      taskId = item.resource.gid;
      console.log("Found task ID in resource:", taskId);
      break;
    }
  }
} else {
  console.log("Webhook data is not an array, checking direct access");

  // Try direct access patterns
  if (webhookData.resource_type === 'task') {
    taskId = webhookData.gid;
  } else if (webhookData.resource && webhookData.resource.resource_type === 'task') {
    taskId = webhookData.resource.gid;
  }
}

// If we still don't have a task ID, try the first item's GID as fallback
if (!taskId && Array.isArray(webhookData) && webhookData.length > 0) {
  // Use the first GID that looks like a task
  const firstItem = webhookData[0];
  if (firstItem.gid) {
    taskId = firstItem.gid;
    console.log("Using first item GID as fallback:", taskId);
  }
}

if (!taskId) {
  throw new Error("Could not find task ID in webhook data");
}

console.log("Final task ID:", taskId);

return [{
  taskId: taskId,
  originalWebhookData: webhookData,
  extractionMethod: "webhook_parsing"
}];

// SAFE: Try multiple ways to access the data
let taskData = null;
let customFields = [];

// Method 1: Direct access
try {
  taskData = $input.first().json;
  if (taskData && taskData.custom_fields) {
    customFields = taskData.custom_fields;
    console.log("Method 1 worked: Direct access");
  }
} catch (e) {
  console.log("Method 1 failed:", e.message);
}

// Method 2: Array access (fallback)
if (!taskData || !customFields.length) {
  try {
    taskData = $input.first().json[0];
    if (taskData && taskData.custom_fields) {
      customFields = taskData.custom_fields;
      console.log("Method 2 worked: Array access");
    }
  } catch (e) {
    console.log("Method 2 failed:", e.message);
  }
}

// If we still don't have data, return debug info
if (!taskData || !customFields.length) {
  return [{
    error: "Could not find custom_fields",
    available_data: Object.keys($input.first().json || {}),
    json_type: typeof $input.first().json,
    raw_data: $input.first().json
  }];
}

// Extract custom field values
let leadStatus = null;
let clientEmail = null;
let clientPhone = null;

for (const field of customFields) {
  if (field.name === 'Lead Status') {
    leadStatus = field.enum_value?.name || field.display_value || null;
  }
  if (field.name === 'Email') {
    clientEmail = field.text_value || field.display_value || null;
  }
  if (field.name === 'Phone Number') {
    clientPhone = field.text_value || field.display_value || null;
  }
}

// Return structured data
return [{
  taskId: taskData.gid || 'unknown',
  taskName: taskData.name || 'unknown',
  leadStatus: leadStatus,
  clientEmail: clientEmail,
  clientPhone: clientPhone,

  // Boolean flags for easier routing
  isReadyToStart: leadStatus === 'Ready to Start',
  isApproved: leadStatus === 'Approved',
  isNoResponse: leadStatus === 'No Response',
  isQuoted: leadStatus === 'Quoted',
  isPaidAndClosed: leadStatus === 'Paid and Closed',

  // Debug info
  method_used: "Direct access method worked",
  custom_fields_count: customFields.length
}];

